// 移动端导航手势组件
export const MobileNavigationGestures: React.FC<{ 
  onSwipeLeft?: () => void;
  onSwipeRight?: () => void;
  onSwipeUp?: () => void;
  onSwipeDown?: () => void;
}> = ({ 
  onSwipeLeft, 
  onSwipeRight, 
  onSwipeUp, 
  onSwipeDown 
}) => {
  const { gesture } = useTouchGestures({ enableSwipe: true });

  useEffect(() => {
    if (gesture?.type === 'swipe') {
      switch (gesture.direction) {
        case 'left':
          onSwipeLeft?.();
          break;
        case 'right':
          onSwipeRight?.();
          break;
        case 'up':
          onSwipeUp?.();
          break;
        case 'down':
          onSwipeDown?.();
          break;
      }
    }
  }, [gesture, onSwipeLeft, onSwipeRight, onSwipeUp, onSwipeDown]);

  return null;
};

// 移动端优化按钮组件
export const MobileOptimizedButton: React.FC<{
  children: React.ReactNode;
  onClick?: () => void;
  className?: string;
  disabled?: boolean;
  variant?: 'primary' | 'secondary' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  touchFeedback?: boolean;
}> = ({ 
  children, 
  onClick, 
  className = '',
  disabled = false,
  variant = 'primary',
  size = 'md',
  touchFeedback = true
}) => {
  const [isPressed, setIsPressed] = useState(false);
  const buttonRef = useRef<HTMLButtonElement>(null);

  // 移动端触摸优化
  const handleTouchStart = useCallback(() => {
    if (touchFeedback) {
      setIsPressed(true);
    }
  }, [touchFeedback]);

  const handleTouchEnd = useCallback(() => {
    if (touchFeedback) {
      setIsPressed(false);
    }
    onClick?.();
  }, [touchFeedback, onClick]);

  const sizeClasses = {
    sm: 'px-3 py-2 text-sm',
    md: 'px-4 py-2 text-base',
    lg: 'px-6 py-3 text-lg'
  };

  const variantClasses = {
    primary: 'bg-blue-600 text-white hover:bg-blue-700 active:bg-blue-800',
    secondary: 'bg-gray-600 text-white hover:bg-gray-700 active:bg-gray-800',
    outline: 'border border-gray-300 text-gray-700 hover:bg-gray-50 active:bg-gray-100'
  };

  return (
    <button
      ref={buttonRef}
      className={`
        ${sizeClasses[size]} 
        ${variantClasses[variant]} 
        ${className}
        rounded-lg font-medium transition-all duration-150 
        transform active:scale-95 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500
        disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none
        ${isPressed ? 'scale-95 shadow-inner' : 'shadow-sm hover:shadow-md'}
        touch-manipulation
      `}
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
      onClick={!touchFeedback ? onClick : undefined}
      disabled={disabled}
      style={{
        WebkitTapHighlightColor: 'transparent',
        touchAction: 'manipulation'
      }}
    >
      {children}
    </button>
  );
};

