import { useEffect, useCallback } from 'react';

interface KeyboardShortcutOptions {
  targetKey: string;
  ctrlKey?: boolean;
  shiftKey?: boolean;
  altKey?: boolean;
  metaKey?: boolean;
  preventDefault?: boolean;
  stopPropagation?: boolean;
}

export const useKeyboardShortcut = (
  callback: () => void,
  options: KeyboardShortcutOptions,
  deps: React.DependencyList = []
) => {
  const {
    targetKey,
    ctrlKey = false,
    shiftKey = false,
    altKey = false,
    metaKey = false,
    preventDefault = true,
    stopPropagation = false
  } = options;

  const handleKeyPress = useCallback(
    (event: KeyboardEvent) => {
      const {
        key,
        ctrlKey: eventCtrlKey,
        shiftKey: eventShiftKey,
        altKey: eventAltKey,
        metaKey: eventMetaKey
      } = event;

      // 检查是否匹配快捷键组合
      const keyMatch = key.toLowerCase() === targetKey.toLowerCase();
      const modifierMatch = 
        ctrlKey === eventCtrlKey &&
        shiftKey === eventShiftKey &&
        altKey === eventAltKey &&
        metaKey === eventMetaKey;

      if (keyMatch && modifierMatch) {
        if (preventDefault) {
          event.preventDefault();
        }
        if (stopPropagation) {
          event.stopPropagation();
        }
        callback();
      }
    },
    [callback, targetKey, ctrlKey, shiftKey, altKey, metaKey, preventDefault, stopPropagation]
  );

  useEffect(() => {
    document.addEventListener('keydown', handleKeyPress);
    return () => {
      document.removeEventListener('keydown', handleKeyPress);
    };
  }, [handleKeyPress]);

  // 重新注册事件监听器当依赖项改变时
  useEffect(() => {
    // 这个 effect 会在 deps 改变时重新运行
  }, deps);
};

